import { Vex } from 'vex-sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  workflowId: 'bedrock-chatbot'
});

export async function verifiedBedrockChat(
  inputText: string,
  sessionId: string,
  context?: any
): Promise<string> {
  // Invoke Bedrock Agent
  const rawResponse = await invokeBedrockAgent(inputText, sessionId);

  // Vex verification with custom checks
  const verified = await vex.verify({
    response: rawResponse,
    context: {
      sessionHistory: context,
      domain: 'ecommerce_chatbot',
      maxHallucinationScore: 0.2,
      piiRules: ['order-\d+', 'email']
    },
    checks: [
      'response_accuracy',
      'conversation_coherence',
      'safety_filtering',
      'pii_protection',
      'hallucination_detection'
    ]
  });

  if (!verified.valid) {
    throw new Error(`Verification failed: ${JSON.stringify(verified.issues)}`);
  }

  return verified.response.content;
}

import vex
from typing import Dict, List

class ChatbotSession:
    def __init__(self):
        self.sessions: Dict[str, List[Dict]] = {}

    @vex.workflow(
        name="bedrock-multi-turn",
        verifications=["conversation_coherence", "response_accuracy"]
    )
    def process_turn(self, session_id: str, input_text: str) -> str:
        # Load session history
        history = self.sessions.get(session_id, [])

        # Get agent response with context
        agent_response = invoke_bedrock_agent(
            input_text, 
            session_id, 
            session_context=history[-5:]  # Last 5 turns
        )

        # Verify coherence across conversation
        verified = vex.verify(
            agent_response,
            context={
                'conversation_history': history,
                'coherence_window': 5,
                'topic_drift_threshold': 0.3
            }
        )

        # Update session
        history.append({
            'input': input_text,
            'output': verified['content'],
            'timestamp': 'now'
        })
        self.sessions[session_id] = history[-10:]  # Keep last 10

        return verified['content']

